mapper.select:
SELECT bu.id, bu.bind_user_time AS brokerageTime, (SELECT SUM(price) FROM trade_brokerage_record r WHERE r.user_id = bu.id AND biz_type = #{bizType} AND r.status = #{status} AND r.deleted = FALSE) AS brokeragePrice, (SELECT COUNT(1) FROM trade_brokerage_record r WHERE r.user_id = bu.id AND biz_type = #{bizType} AND r.status = #{status} AND r.deleted = FALSE) AS brokerageOrderCount, (SELECT COUNT(1) FROM trade_brokerage_user c WHERE c.bind_user_id = bu.id AND c.deleted = FALSE) AS brokerageUserCount FROM trade_brokerage_user AS bu
bu.deleted = false
and bu.id in
#{id}
ORDER BY brokerageUserCount ${sortingField.order}
ORDER BY brokerageOrderCount ${sortingField.order}
ORDER BY brokeragePrice ${sortingField.order}
ORDER BY bu.bind_user_time DESC

SELECT COUNT(*) AS user_count
FROM trade_brokerage_user tb
         INNER JOIN member_user mu ON tb.id = mu.id
WHERE tb.bind_user_id = #{userId}
  AND mu.level_id = #{levelId}

SELECT COUNT(*) FROM trade_brokerage_user
WHERE bind_user_id = #{userId}
AND deleted = 0

    AND brokerage_enabled = #{enabled}

SELECT COUNT(*) FROM trade_brokerage_user u
LEFT JOIN member_user m ON u.id = m.id
WHERE u.bind_user_id = #{userId}
AND u.deleted = 0
AND u.create_time >= #{createTime}

    AND u.brokerage_enabled = #{enabled}


    AND m.level_id = #{level}

WITH RECURSIVE descendants AS ( SELECT u.id, u.bind_user_id, u.create_time, u.brokerage_enabled, 1 AS depth FROM trade_brokerage_user u WHERE u.bind_user_id = #{userId} AND u.deleted = 0
UNION ALL
SELECT child.id, child.bind_user_id, child.create_time, child.brokerage_enabled, d.depth + 1 FROM trade_brokerage_user child JOIN descendants d ON child.bind_user_id = d.id WHERE child.deleted = 0 ) SELECT COUNT(*) FROM descendants d LEFT JOIN member_user m ON d.id = m.id WHERE d.depth > 1 AND d.create_time >= #{createTime}
AND d.brokerage_enabled = #{enabled}
AND m.level_id = #{level}

WITH RECURSIVE temp_tree AS ( -- 初始查询：获取直接下级 SELECT u.id FROM trade_brokerage_user u WHERE u.bind_user_id = #{userId} AND u.deleted = 0
UNION ALL
-- 递归查询：获取下级的下级 SELECT child.id FROM trade_brokerage_user child JOIN temp_tree t ON child.bind_user_id = t.id WHERE child.deleted = 0 ) SELECT u.* FROM temp_tree t JOIN trade_brokerage_user u ON t.id = u.id LEFT JOIN member_user m ON u.id = m.id
AND m.level_id = #{level}
AND ( m.nickname LIKE CONCAT('%', #{nickname}, '%') OR m.mobile LIKE CONCAT('%', #{nickname}, '%') OR CAST(u.id AS CHAR) LIKE CONCAT('%', #{nickname}, '%') )
ORDER BY u.create_time DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT u.* FROM trade_brokerage_user u LEFT JOIN member_user m ON u.id = m.id WHERE u.bind_user_id = #{userId} AND u.brokerage_enabled = 1 AND u.deleted = 0
AND m.level_id = #{level}
AND ( m.nickname LIKE CONCAT('%', #{nickname}, '%') OR m.mobile LIKE CONCAT('%', #{nickname}, '%') OR CAST(u.id AS CHAR) LIKE CONCAT('%', #{nickname}, '%') )
ORDER BY u.create_time DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM trade_brokerage_user u LEFT JOIN member_user m ON u.id = m.id WHERE u.bind_user_id = #{userId} AND u.brokerage_enabled = 1 AND u.deleted = 0
AND m.level_id = #{level}
AND ( m.nickname LIKE CONCAT('%', #{nickname}, '%') OR m.mobile LIKE CONCAT('%', #{nickname}, '%') OR CAST(u.id AS CHAR) LIKE CONCAT('%', #{nickname}, '%') )

WITH RECURSIVE descendants AS ( SELECT u.id, u.bind_user_id, 1 AS depth FROM trade_brokerage_user u WHERE u.bind_user_id = #{userId} AND u.deleted = 0
UNION ALL
SELECT child.id, child.bind_user_id, d.depth + 1 FROM trade_brokerage_user child JOIN descendants d ON child.bind_user_id = d.id WHERE child.deleted = 0 ) SELECT u.* FROM descendants d JOIN trade_brokerage_user u ON d.id = u.id LEFT JOIN member_user m ON u.id = m.id WHERE d.depth > 1 AND u.brokerage_enabled = 1
AND m.level_id = #{level}
AND ( m.nickname LIKE CONCAT('%', #{nickname}, '%') OR m.mobile LIKE CONCAT('%', #{nickname}, '%') OR CAST(u.id AS CHAR) LIKE CONCAT('%', #{nickname}, '%') )
ORDER BY u.create_time DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT bind_user_id as userId, COUNT(*) as childCount FROM trade_brokerage_user WHERE bind_user_id IN
#{userId}
AND deleted = 0 GROUP BY bind_user_id
